import io
import os
import json
from typing import List, Optional, Tuple

import torch
import torch.nn.functional as F
from PIL import Image

from fastapi import FastAPI, UploadFile, File, HTTPException
from fastapi.responses import JSONResponse

DEFAULT_MODEL_PATH = os.getenv("MODEL_PATH", "model.pt")
DEFAULT_CLASSES_PATH = os.getenv("CLASSES_PATH", "")
DEFAULT_DEVICE = os.getenv("DEVICE", "cpu")
DEFAULT_TOPK = int(os.getenv("TOPK", "1"))

app = FastAPI(title="Image Classification API", version="1.0.0")

_model = None
_device = None
_class_names: Optional[List[str]] = None


def _load_class_names(path: str) -> Optional[List[str]]:
    if not path:
        return None
    if not os.path.exists(path):
        return None
    with open(path, "r", encoding="utf-8") as f:
        if path.lower().endswith(".json"):
            data = json.load(f)
            if isinstance(data, dict):
                keys = list(data.keys())
                if all(k.isdigit() for k in keys):
                    return [data[str(i)] for i in range(len(keys))]
                return [data[k] for k in keys]
            if isinstance(data, list):
                return data
            return None
        return [line.rstrip("\n") for line in f if line.strip()]


def _load_model(model_path: str, device: str):
    global _model, _device, _class_names
    _device = torch.device(device)
    obj = torch.load(model_path, map_location=_device)

    if isinstance(obj, torch.nn.Module):
        model = obj
    elif isinstance(obj, dict):
        if "model" in obj and isinstance(obj["model"], torch.nn.Module):
            model = obj["model"]
        else:
            raise RuntimeError("Unsupported model file format. Expected a torch.nn.Module or dict containing 'model'.")
    else:
        raise RuntimeError("Unsupported model file format.")

    model.eval()
    model.to(_device)
    _model = model

    _class_names = _load_class_names(DEFAULT_CLASSES_PATH)


@app.on_event("startup")
def _startup():
    model_path = DEFAULT_MODEL_PATH
    if not os.path.exists(model_path):
        raise RuntimeError(f"MODEL_PATH not found: {model_path}")
    _load_model(model_path, DEFAULT_DEVICE)


def _infer_from_image_bytes(image_bytes: bytes, topk: int = 1) -> Tuple[List[int], List[float]]:
    img = Image.open(io.BytesIO(image_bytes))
    x = torch.tensor(list(img.getdata()))
    if img.mode in ("L", "I;16", "I", "F"):
        x = x.view(img.size[1], img.size[0], 1)
    else:
        x = x.view(img.size[1], img.size[0], -1)
    x = x.to(torch.float32)
    x = x.permute(2, 0, 1).unsqueeze(0).to(_device)

    with torch.no_grad():
        logits = _model(x)
        if isinstance(logits, (tuple, list)):
            logits = logits[0]
        probs = F.softmax(logits, dim=-1)
        k = max(1, int(topk))
        k = min(k, probs.shape[-1])
        confs, idxs = torch.topk(probs, k=k, dim=-1)
        idxs = idxs.squeeze(0).detach().cpu().tolist()
        confs = confs.squeeze(0).detach().cpu().tolist()
        if isinstance(idxs, int):
            idxs = [idxs]
        if isinstance(confs, float):
            confs = [confs]
        return idxs, confs


def _format_result(indices: List[int], confidences: List[float]):
    results = []
    for i, c in zip(indices, confidences):
        label = _class_names[i] if (_class_names is not None and 0 <= i < len(_class_names)) else str(i)
        results.append({"class": label, "index": int(i), "confidence": float(c)})
    return results


@app.post("/predict")
async def predict(file: UploadFile = File(...), topk: int = DEFAULT_TOPK):
    if _model is None:
        raise HTTPException(status_code=500, detail="Model not loaded")

    image_bytes = await file.read()
    try:
        idxs, confs = _infer_from_image_bytes(image_bytes, topk=topk)
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

    results = _format_result(idxs, confs)
    if topk <= 1:
        return JSONResponse(content=results[0])
    return JSONResponse(content={"predictions": results})


@app.get("/health")
def health():
    return {"status": "ok", "device": str(_device), "model_loaded": _model is not None}


